1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Edge: empty
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // Base premiums per item type (with first-insurance surcharge per spec)
15	  it.todo("single sword, newcomer, no previous contract → 100 base + 10 first + 5 fee = 115 G");
16	  it.todo("single amulet, newcomer, no previous contract → 60 base + 6 first + 5 fee = 71 G");
17	  it.todo("single staff, newcomer, no previous contract → 80 base + 8 first + 5 fee = 93 G");
18	  it.todo("single potion, newcomer, no previous contract → 40 base + 4 first + 5 fee = 49 G");
19	
20	  // Components — basic
21	  it.todo("1 rune → 25 G base + 2.5 first → 28 G premium (rounded up) + 5 fee = 33 G");
22	  it.todo("2 runes → 50 G base premium (no block)");
23	  it.todo("3 runes → 60 G base premium (block applies)");
24	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
25	  it.todo("7 runes → 175 G base premium (2 standalone + … no block forms from 7)");
26	
27	  // Alike components clarification
28	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block — different types)");
29	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
30	
31	  // Modifier scope on multi-item policies
32	  it.todo("cursed sword + plain amulet, newcomer → 100 + 60 base = 160, curse adds 50 (on sword's base only) = 210 before further modifiers + fee");
33	
34	  // Modifier thresholds — premiums
35	  it.todo("customer with exactly 2 years with MHPCO → loyalty discount applies");
36	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
37	  it.todo("cursed sword with exactly enchantment 5 → both surcharges apply");
38	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
39	
40	  // Rounding in MHPCO's favor — premium
41	  it.todo("a premium calculation that yields 197.5 G → final premium 198 G (rounded up)");
42	
43	  // Integration examples
44	  it.todo("Newcomer with cursed sword (steel, enchantment 3): 0 years, no previous → premium 165 G");
45	  it.todo("Long-standing customer's second contract: 3 years, second quote, cursed sword enchantment 7 → 160 G");
46	
47	  // Edge — unknown item type at quote
48	  it.todo("quote with unknown item type (e.g. broomstick) → throws / non-zero exit; no results written");
49	
50	  // Claim — basics
51	  it.todo("regular sword (steel, enchantment 3), damage 500 G → payout 400 G (full minus 100 G deductible)");
52	  it.todo("damage to a rune (insurance value 250 G), damage 200 G → payout 100 G (no special clause)");
53	
54	  // Claim — enchantment threshold
55	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
56	
57	  // Claim — dragon material
58	  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (full reimbursement, then deductible)");
59	
60	  // Claim — enchantment vs dragon material
61	  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins, then deductible)");
62	  it.todo("dragon-material sword, exactly enchantment 8, damage 1000 G → payout 400 G");
63	
64	  // Deductible per damage event (per damaged item)
65	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible per item)");
66	
67	  // Multiple items of the same type
68	  it.todo("two swords policy → insurance sum 2000 G, cap 4000 G");
69	  it.todo("two swords policy with two sword damage entries → each damage gets its own deductible");
70	  it.todo("policy covers only one sword but damages contain two sword entries → non-zero exit / error");
71	
72	  // Cap exhaustion
73	  it.todo("policy with sword and amulet → insurance sum 1600 G, cap 3200 G");
74	  it.todo("cursed sword (premium with modifiers 165 G) → cap 2000 G (based on unmodified insurance value)");
75	  it.todo("sword + 3 runes (a block) → insurance sum 1750 G; block discount does not affect insurance sum");
76	  it.todo("sword insured (cap 2000 G), two successive 1500 G claims → first payout 1400 G remainingCap 600 G, second payout 600 G remainingCap 0 G");
77	
78	  // Rounding — payout
79	  it.todo("payout calculation that yields 350.5 G → final payout 350 G (rounded down)");
80	
81	  // Claim errors
82	  it.todo("claim references damage entry for item not in policy → non-zero exit / error");
83	  it.todo("claim references damage entry with unknown item type → non-zero exit / error");
84	  it.todo("claim contains damage entry with amount -200 → non-zero exit / error");
85	});
